const leads = $('Get Leads').all();
const requests = $('Get Tutoring Requests').all();
const costsSummary = $('Get Costs Summary').first().json;
const costsByAgent = $('Get Costs By Agent').all();

// Calcular timestamp de hace 24 horas
const now = new Date();
const past24h = new Date(now.getTime() - 24 * 60 * 60 * 1000);

// 1. Procesamiento de Leads
let newLeads24h = 0;
const supportTypeCounts = {};
const gradeCounts = {};
const subjectCounts = {};

leads.forEach(item => {
  const lead = item.json;
  const createdAt = lead.created_at ? new Date(lead.created_at) : null;
  if (createdAt && createdAt >= past24h) {
    newLeads24h++;

    const supportType = lead.support_type || 'No especificado';
    supportTypeCounts[supportType] = (supportTypeCounts[supportType] || 0) + 1;

    const grade = lead.grade || 'No especificado';
    gradeCounts[grade] = (gradeCounts[grade] || 0) + 1;

    const subject = lead.subject || 'No especificado';
    subjectCounts[subject] = (subjectCounts[subject] || 0) + 1;
  }
});

// 2. Procesamiento de Solicitudes de Tutoría
let newRequests24h = 0;
const requestStatusCounts = {
  'new': 0,
  'contacted': 0,
  'scheduled': 0,
  'completed': 0,
  'cancelled': 0
};

requests.forEach(item => {
  const req = item.json;
  const createdAt = req.created_at ? new Date(req.created_at) : null;
  if (createdAt && createdAt >= past24h) {
    newRequests24h++;
  }

  const status = req.status || 'new';
  requestStatusCounts[status] = (requestStatusCounts[status] || 0) + 1;
});

// 3. Procesamiento de Costos de IA
const totalSpendUSD = (costsSummary.spendCents || 0) / 100;
const totalBudgetUSD = (costsSummary.budgetCents || 0) / 100;
const utilizationPercent = costsSummary.utilizationPercent || 0;

let agentCostsMarkdown = '';
costsByAgent.forEach(item => {
  const agent = item.json;
  const costUSD = (agent.costCents || 0) / 100;
  if (costUSD > 0 || agent.inputTokens > 0) {
    agentCostsMarkdown += `| ${agent.agentName} | $${costUSD.toFixed(4)} | ${agent.inputTokens.toLocaleString()} | ${agent.outputTokens.toLocaleString()} |\n`;
  }
});

if (!agentCostsMarkdown) {
  agentCostsMarkdown = '| Ninguno | $0.00 | 0 | 0 |\n';
}

// 4. Formatear detalle por canal
let channelsMarkdown = '';
Object.keys(supportTypeCounts).forEach(channel => {
  channelsMarkdown += `- **${channel}**: ${supportTypeCounts[channel]} leads\n`;
});
if (!channelsMarkdown) channelsMarkdown = 'No se registraron nuevos leads.\n';

// Formatear grados
let gradesMarkdown = '';
Object.keys(gradeCounts).forEach(grade => {
  gradesMarkdown += `- **${grade}**: ${gradeCounts[grade]} leads\n`;
});
if (!gradesMarkdown) gradesMarkdown = 'N/A\n';

// Formatear materias
let subjectsMarkdown = '';
Object.keys(subjectCounts).forEach(sub => {
  subjectsMarkdown += `- **${sub}**: ${subjectCounts[sub]} leads\n`;
});
if (!subjectsMarkdown) subjectsMarkdown = 'N/A\n';

// 5. Construir reporte final Markdown
const todayStr = now.toISOString().split('T')[0];
const markdownReport = `### 📊 INFORME DIARIO DE OPERACIONES Y COSTOS - CEDETU (${todayStr})\n\n#### 1. Métrica de Captación de Leads (Últimas 24 Horas)\n*   **Total de Nuevos Leads:** ${newLeads24h}\n*   **Detalle por Canal / Medio de Captación:**\n${channelsMarkdown}\n*   **Distribución por Nivel Académico:**\n${gradesMarkdown}\n*   **Distribución por Materia de Interés:**\n${subjectsMarkdown}\n\n#### 2. Estado de Solicitudes de Tutoría\n*   **Nuevas solicitudes en últimas 24h:** ${newRequests24h}\n*   **Acumulado histórico por Estado:**\n    - **Nuevas (new):** ${requestStatusCounts['new'] || 0}\n    - **Contactadas (contacted):** ${requestStatusCounts['contacted'] || 0}\n    - **Agendadas (scheduled):** ${requestStatusCounts['scheduled'] || 0}\n    - **Completadas (completed):** ${requestStatusCounts['completed'] || 0}\n    - **Canceladas (cancelled):** ${requestStatusCounts['cancelled'] || 0}\n\n#### 3. Control de Costos de API de IA (Paperclip)\n*   **Gasto Acumulado Mensual de la Empresa:** $${totalSpendUSD.toFixed(2)} USD\n*   **Presupuesto Mensual:** $${totalBudgetUSD.toFixed(2)} USD (Utilización: ${utilizationPercent.toFixed(1)}%)\n\n**Desglose detallado por Agente Operativo:**\n\n| Agente | Costo Total (USD) | Tokens Entrada | Tokens Salida |\n| :--- | :--- | :--- | :--- |\n${agentCostsMarkdown}\n\n*Informe generado automáticamente por el Reporting Agent a las 08:00 AM. Para cualquier duda, responde a este Issue.*`;

return [{
  json: {
    today: todayStr,
    markdownReport
  }
}];
